mapper.select:
SELECT p.post_id, p.board_type, p.dept_id, d.dept_name, p.title, p.created_by, p.view_count, p.is_pinned, p.created_at, p.updated_at FROM platform_v3.bd_post p LEFT JOIN platform_v3.org_department d ON p.dept_id = d.dept_id WHERE p.deleted_at IS NULL AND p.board_type = #{boardType} AND p.dept_id = #{deptId}
AND (p.title LIKE '%' || #{keyword} || '%' OR p.content LIKE '%' || #{keyword} || '%')
ORDER BY p.is_pinned DESC, p.created_at DESC LIMIT 100

mapper.update:
UPDATE platform_v3.bd_post
SET deleted_at = NOW(), deleted_by = #{deletedBy}
WHERE post_id = #{postId}
